import { useLayoutEffect, useMemo, useState } from 'react';
import { FormattedMessage } from 'react-intl';

import {
  ChevronDownSmallIcon,
  ChevronUpSmallIcon,
} from '@dynatrace/strato-icons';

import type { ButtonProps } from '../../../buttons/button/Button.js';
import { useId } from '../../../core/hooks/useId.js';
import { getVirtualFocusStyles } from '../../../core/styles/getVirtualFocusStyles.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { filterFieldMessages } from '../messages.js';
import { useFilterFieldContext } from './useFilterFieldContext.js';
import type { FlattenedSuggestionItem } from '../suggestions/Suggestion.types.js';
import {
  getCurrentFocusableListItemByIndex,
  getCurrentFocusableListItemIndex,
} from '../utils/get-next-suggestion.js';

/**
 * Slice result type.
 * @internal
 */
type SliceResult<T> = { items: T[]; isSliced: boolean };

/**
 * Slice function type.
 * @internal
 */
type SliceFn<T> = (items: T[], count: number) => SliceResult<T>;

/** @internal */
export function useShowMore<T>(props: {
  items: T[];
  primaryCount: number;
  sliceFn?: SliceFn<T>;
}): {
  items: T[];
  isSliced: boolean;
  isExpanded: boolean;
  controlProps: ButtonProps<'button'>;
} {
  const { items, primaryCount, sliceFn: _propSliceFn } = props;
  const sliceFn: SliceFn<T> = _propSliceFn ?? defaultSlice;

  const [isExpanded, setIsExpanded] = useState(false);
  const [pendingNextSuggestionIndex, setPendingNextSuggestionIndex] = useState<
    number | null
  >(null);

  const { focusedListItem, handleNextSuggestion, suggestionsOverlayRef } =
    useFilterFieldContext();

  const id = useId();

  useLayoutEffect(() => {
    if (pendingNextSuggestionIndex !== null) {
      const element = getCurrentFocusableListItemByIndex(
        suggestionsOverlayRef,
        pendingNextSuggestionIndex,
      );
      handleNextSuggestion(element);

      setPendingNextSuggestionIndex(null);
    }
  }, [pendingNextSuggestionIndex, suggestionsOverlayRef, handleNextSuggestion]);

  const controlProps = useMemo<ButtonProps<'button'>>(
    () => ({
      // Role needs to be option, because otherwise NVDA will crash if the activeDecendant of a listbox is anything other than a role option or group.
      role: 'option',
      onClick: (event) => {
        event.preventDefault();
        event.stopPropagation();

        const isKeyboard =
          event.detail === 0 || event.nativeEvent instanceof KeyboardEvent;

        if (isExpanded || !isKeyboard) {
          setIsExpanded((previousState) => !previousState);
          return;
        }

        const index = getCurrentFocusableListItemIndex(
          suggestionsOverlayRef,
          focusedListItem?.id,
        );

        setIsExpanded((previousState) => !previousState);

        // Set the index for useLayoutEffect to handle after DOM update
        setPendingNextSuggestionIndex(index ?? null);
      },
      id,
      'data-strato-filter-field-virtual-focus-id': id,
      'data-strato-filter-field-virtual-focus-type': 'button',
      'data-dt-name': 'ShowMoreLess',
      'data-dt-properties': `state:${isExpanded ? 'less' : 'more'}`,
      className: getVirtualFocusStyles(id === focusedListItem?.id).className,
      width: 'full',
      textAlign: 'start',
      children: (
        <Flex gap={2} as="span" paddingLeft={4}>
          <FormattedMessage
            {...filterFieldMessages.suggestions.showMore}
            values={{ isExpanded }}
          />
          {isExpanded ? <ChevronUpSmallIcon /> : <ChevronDownSmallIcon />}
        </Flex>
      ),
    }),
    [focusedListItem?.id, id, isExpanded, suggestionsOverlayRef],
  );

  const { items: resultItems, isSliced } = useMemo(
    () => sliceFn(items, primaryCount),
    // Only recompute when the suggestions themselves change to avoid flashing
    // when the primaryCount toggles (e.g., empty vs filled input) without data changes.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [items, sliceFn],
  );

  if (primaryCount === -1) {
    return {
      items,
      isSliced: false,
      isExpanded,
      controlProps,
    };
  }

  return {
    items: isExpanded ? items : resultItems,
    isSliced,
    controlProps,
    isExpanded,
  };
}

/**
 * Simple array slicing with +1 buffer to avoid showing "show more" if there is only one additional item.
 * @internal
 */
function defaultSlice<T>(items: T[], count: number): SliceResult<T> {
  if (items.length <= count + 1) {
    return { items, isSliced: false };
  }
  return { items: items.slice(0, count), isSliced: true };
}

/**
 * Slice the flat suggestions in case they exceed the defined limit of suggestions
 * shown. Group headers don't count toward the  suggestion limit, but will only be rendered
 * if a suggestion is still visible afterwards.
 * Suggestions will only be sliced if there are at least two more suggestions than
 * the defined count.
 *
 * Example with a count of 5 that explains why we do it that way:
 * - 5 suggestions: we show all suggestions (they're still below the count that was
 * specified)
 * - 6 suggestions: we show all suggestions (adding a show more button would only
 * redundantly collapse one suggestion)
 * - 7 suggestions: we show only five suggestions + a show more button to reveal the
 * additional suggestions
 * @internal
 */
export function sliceFlattenedSuggestions(
  suggestions: FlattenedSuggestionItem[],
  count: number,
): SliceResult<FlattenedSuggestionItem> {
  if (count === -1) {
    return { items: suggestions, isSliced: false };
  }

  let totalSuggestionCount = 0;
  for (const item of suggestions) {
    if (item.kind !== 'group-header') {
      totalSuggestionCount++;
    }
  }

  // Return original suggestions if they fit within the limit.
  if (totalSuggestionCount <= count + 1) {
    return { items: suggestions, isSliced: false };
  }

  let visibleCount = 0;
  const itemsShown: FlattenedSuggestionItem[] = [];

  for (const item of suggestions) {
    // Add group header, but don't increase the visible count, since group headers don't count towards the suggestion limit.
    if (item.kind === 'group-header') {
      itemsShown.push(item);
      continue;
    }

    if (visibleCount >= count) {
      break;
    }

    itemsShown.push(item);
    visibleCount++;
  }

  // Trim trailing group-header.
  if (
    itemsShown.length > 0 &&
    itemsShown[itemsShown.length - 1].kind === 'group-header'
  ) {
    itemsShown.pop();
  }

  return { items: itemsShown, isSliced: true };
}
